$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$items=(& (Join-Path $root 'scripts\get-assistant-adapters.ps1') -Json|Out-String)|ConvertFrom-Json;if(@($items).Count -ne 3 -or @($items|Where-Object {!$_.verified -or $_.support -ne 'supported'}).Count -or @($items|Where-Object {$_.limitations -notmatch 'No other assistant'}).Count){throw 'Assistant adapter contract failed.'};foreach($relative in @('README.md','examples\claude-code\README.md')){$text=Get-Content -Raw -LiteralPath (Join-Path $root $relative);foreach($term in @('unverified guidance example','not a tested adapter','Codex, Cursor, and the generic AGENTS-compatible target only')){if($text -notmatch [regex]::Escape($term)){throw "Adapter transparency term '$term' missing from $relative."}}};Write-Host 'Assistant adapter tests passed'
